from flask import Flask, request, jsonify
import numpy as np
from sklearn.preprocessing import LabelEncoder
from sklearn.svm import SVC
from face_recognition import load_image_file, face_encodings

app = Flask(__name__)

# Dummy data for demonstration purposes
employee_photos_paths = ['path/to/photo1.jpg', 'path/to/photo2.jpg']
employee_names = ['John Doe', 'Jane Smith']

def train_model():
    encodings = []
    labels = []

    for photo_path, name in zip(employee_photos_paths, employee_names):
        image = load_image_file(photo_path)
        encoding = face_encodings(image)[0]
        encodings.append(encoding)
        labels.append(name)

    encoder = LabelEncoder()
    encoded_labels = encoder.fit_transform(labels)

    model = SVC(probability=True)
    model.fit(encodings, encoded_labels)
    
    return model, encoder

model, encoder = train_model()

@app.route('/recognize', methods=['POST'])
def recognize():
    if 'photo' not in request.files:
        return jsonify({'error': 'No photo provided'}), 400
    
    photo = request.files['photo']
    image = load_image_file(photo)
    
    try:
        encoding = face_encodings(image)[0]
        probabilities = model.predict_proba([encoding])[0]
        
        result = {name: prob for name, prob in zip(encoder.classes_, probabilities)}
        return jsonify(result)
    except IndexError:
        return jsonify({'error': 'No face detected'}), 400

if __name__ == '__main__':
    app.run(debug=True)